import React from 'react';
import { internships } from '../../data/mockData';

export default function MyApplications() {
  // Mocking that the user applied to the first 2 internships
  const appliedInternships = [
    { ...internships[0], status: 'In Review', date: '2 days ago' },
    { ...internships[2], status: 'Applied', date: '1 week ago' },
  ];

  return (
    <div className="page-enter">
      <h1 className="dashboard-title">My Applications</h1>
      <div>
        {appliedInternships.map(app => (
          <div key={app.id} className="app-card">
            <div className="app-card__info">
              <h4>{app.role} at {app.company}</h4>
              <p>Applied {app.date} • {app.location}</p>
            </div>
            <div>
              <span className={`status-badge ${app.status === 'Applied' ? 'status-applied' : 'status-review'}`}>
                {app.status}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
